    end
    CS.AppConst.NetworkReceiveLimit = maxRecv
    CS.AppConst.NetworkSendLimit = 6

end

function LNetManager:Dispose()
    local waitConnectTimer = self._waitConnectTimer
    if waitConnectTimer then
        waitConnectTimer:Destroy()
        self._waitConnectTimer = nil
    end
    
    local messages = self._protoMessages
    if messages then
        for k, v in pairs(messages) do
            messages[k] = nil
            for m,n in ipairs(v) do
                n.removed = true
                n.func = nil
                n.target = nil
            end
        end
        self._protoMessages = nil
    end
    
    local waitMsgMap = self._waitMsgMap
    if waitMsgMap then
        for k, v in pairs(waitMsgMap) do
            waitMsgMap[k] = nil
            local stream = v.stream
            if stream then
                stream:Clear()
            end
        end
    end
    LxBaseMgr.Dispose(self)
end

function LNetManager:SetServerTime(serverTime)
    self._serverTime64 = serverTime
