end

function LNetManager:FireMessage(msgId, protoStream, ret, errorCode, errorArgs)
    local messages = self._protoMessages
    local methodList = messages[msgId]
    if not methodList then
        if LOG_INFO_ENABLED then
            printInfoN2(NETWORK_LOG_TAG, string.format("proto message is not register %8d", msgId))
        end
        return
    end

    local removeList = {}
    local bRemove = false
    local len = #methodList
    for k = 1, len do
        local data = methodList[k]
        if data.removed then
            table.insert(removeList, k)
            bRemove = true
        else
            if data.target ~= nil then
                ccXpcall(data.func, data.target, protoStream, ret, errorCode, errorArgs)
            else
                ccXpcall(data.func, protoStream, ret, errorCode, errorArgs)
            end

        end
    end
    if bRemove then
        for k=#removeList, 1, -1 do
            table.remove(methodList, removeList[k])
        end
    end
end

function LNetManager:AddMsgListener(msgId, method, target)
    if not msgId then
        if ENABLE_PROTO_LOG then
            printInfoN2(NETWORK_LOG_TAG, "AddMsgListener ---> msgId is nil")
        end
        return
    end

    local methodList = self._protoMessages[msgId]
    if methodList then
        table.insert(methodList, {func=method, target = target})
    else
        self._protoMessages[msgId] = { 
            {func = method, target = target}
        }
    end
end

function LNetManager:RemoveMsgListener(msgId, method, target)
    if not self._protoMessages then
        print("xxx-------" .. tostring(msgId))
    end
    local methodList = self._protoMessages[msgId]
    if not methodList then return end

    for k,v in ipairs(methodList) do
        if v.func == method and v.target == target then
            v.func = nil
            v.target = nil
            v.removed = true
            break
        end
    end
end

function LNetManager:SetAccount(account)
