function LNetManager:SetConnectPara(ipAddress, port)
    self._ipAddress = ipAddress
    self._port = port

    self._isWebSocket = CS.IsWebGL() or LGameSettings.forceWebSocket == "true"

    ---检测是否强制使用wss
    self._isForceWss = false
    if self._isWebSocket then
        local urlList = LGameSettings.platformUrlList or {}
        local url = urlList[1]
        if not string.isempty(url) and string.startswith(url, "https://") then
            self._isForceWss = true
            LogWarn("websocket force wss")
        end

        if LOG_INFO_ENABLED then
            printInfoN2(NETWORK_LOG_TAG,  "network is us websocket ... ")
        end
    end
end

function LNetManager:Connect()
    if self:IsConnected() then
        if LOG_INFO_ENABLED then
            printInfoN2(NETWORK_LOG_TAG,  "network is connected already... ")
        end
        return
    end

    self:PrepareNetwork()
    self:ConnectInternal()
end

function LNetManager:PrepareNetwork()
    self._networkId = YXNetMgr:PrepareNetwork(self._isWebSocket and 1 or 0)
    self._connectedNum = 0
    self._connectCounter = 0
    self._isNetworkClosing = false
end

function LNetManager:ConnectInternal()
    self._isDelayReconnect = false

    if LOG_INFO_ENABLED then
        printInfoN2(NETWORK_LOG_TAG,  "connect to "..self._ipAddress..":"..self._port)
    end

    local ipAddress = self._ipAddress
    local port = self._port
    if self._isWebSocket then
        local isWs = not self._isForceWss or LGameSettings.isWs
        if isWs then
            ipAddress = string.replace("ws://#a1#:#a2#/ws", ipAddress, port)
        else
            ipAddress = string.replace("wss://#a1#:#a2#/ws", ipAddress, port)
        end
    end
    if not self._isWebSocket then
        self:StartTimer(_NetTimer.WaitConnectTimeOut, self._timeout * 0.001, function()
            if LOG_INFO_ENABLED then
                printInfoN2(NETWORK_LOG_TAG, "network is connected timeout check by lua")
            end
            -- local socketId = self._networkId
            -- if (socketId > 0) then
            --     YXNetMgr:DisposeConnect()
            -- end
            self:StopTimer(_NetTimer.WaitConnectTimeOut)
            self:OnConnectFail()
        end , false, 1)
    end

    YXNetMgr:Connect(ipAddress, self._port, self._timeout)
end

function LNetManager:Reconnect()
    self._isDelayReconnect = false
    if self:IsConnected() then
        self._isReconnecting = false
        if LOG_INFO_ENABLED then
            printInfoN2(NETWORK_LOG_TAG, "network is connected already , cannot reconnect ...")
        end
        return
    end

    self._isInitServerTime = false
    local connectCounter = self._connectCounter
    if (connectCounter < 0) then
        self._isReconnecting = false
        if LOG_INFO_ENABLED then
            printInfoN2(NETWORK_LOG_TAG, "not allow to reconnect ...")
        end
        return
    end

    if connectCounter >= SOCKET_RECONNECT_MAX then
        self._connectCounter = 0
        self._isReconnecting = false
        if LOG_INFO_ENABLED then
            printInfoN2(NETWORK_LOG_TAG, string.format("reconnect failed in %d times", connectCounter))
        end
        self:OnReconnectFailed()
        return
    end

    self._isReconnecting = true
    self._connectCounter = connectCounter + 1
    local reconnectWaitSec = connectCounter <= 0 and 2 or 3
    self._isNewConnect = false

    self:DelayReconnect(self._connectCounter,reconnectWaitSec)

end

function LNetManager:DelayReconnect(connectCounter, reconnectWaitSec)
    if LOG_INFO_ENABLED then
        printInfoN2(NETWORK_LOG_TAG, "start reconnect ...")
        printInfoN2(NETWORK_LOG_TAG, string.format("the %d time reconnected start after %d second ",connectCounter + 1,reconnectWaitSec))
    end
    self._isDelayReconnect = true

    self:StartTimer(_NetTimer.Reconnect, reconnectWaitSec, function()
        GF.StartWaitReConnect(connectCounter, SOCKET_RECONNECT_MAX)
        self._isDelayReconnect = false
        if not self:IsConnected() then
            self:ConnectInternal()
        end
    end,false,1)
end

function LNetManager:RecreateAndConnect()
    self:Recreate()
    self._isNewConnect = true
    self:Connect()
end
function LNetManager:Recreate()
    local socketId = self._networkId
    if (socketId > 0) then
        YXNetMgr:DisposeConnect()
    end
    self:StopTimer(_NetTimer.Reconnect)
    self:StopTimer(_NetTimer.WaitConnectTimeOut)
    self._isDelayReconnect = false

    self._isNetworkClosing = false
    self._isConnected = false
    self._isNewConnect = false
    self._connectCounter = 0
end

function LNetManager:StopConnect(tips)
    self._connectCounter = -1
    self._isNetworkClosing = true
    self._isConnected = false
    self._networkId = -1
    self:StopTimer(_NetTimer.Reconnect)
    self:StopTimer(_NetTimer.WaitConnectTimeOut)
    self._isDelayReconnect = false
    YXNetMgr:DisposeConnect()

    if(tips) then
        if LOG_INFO_ENABLED then
            printInfoN2(NETWORK_LOG_TAG, string.format("[quit network stop connect]%s", FormatLogWithColor(tostring(tips), "ff0001ff")))
        end
    end
end

function LNetManager:OnConnectFail()

    local isConnected = self._isConnected
    if not isConnected and not self._isReconnecting then
        self:StopTimer(_NetTimer.Reconnect)
        self:Reconnect()
    elseif self._isReconnecting and not self._isDelayReconnect then
        self:StopTimer(_NetTimer.Reconnect)
        self:Reconnect()
    else

    end
end

function LNetManager:OnReconnectFailed()
    self:ShowNetBlock(false)

    GF.OpenWndDebug("UISistemTip",{refId=40008, leftFunc=function() QuitGame() end, func=function() self:RecreateAndConnect() end})
end

function LNetManager:OnConnected()
    self._isConnected = true
    self._reconnectTimeOld = Time.realtimeSinceStartup

    if self._isReconnecting then
        self._connectedNum = self._connectedNum + 1
        self._isReconnecting = false
    end
    if self._isNewConnect and self._isEnableResend  then
        self._connectedNum = self._connectedNum + 1
        self._isNewConnect = false
    end
    if LOG_INFO_ENABLED then
        printInfoN2(NETWORK_LOG_TAG, "network connected ...")
    end

    gLGameLogin:Step_AuthServer()
end

function LNetManager:OnNetworkLost(retCode)
    if LOG_INFO_ENABLED then
        printInfoN2(NETWORK_LOG_TAG, string.format("network lost | ret = %s...", tostring(retCode)))
    end

    local time = Time.realtimeSinceStartup
    if self._reconnectTimeOld > 0 and time - self._reconnectTimeOld < 2 then
        self._isConnected = false
        self:StopConnect()
        self:ShowNetBlock(false)

        GF.OpenWndDebug("UISistemTip",{refId=40008, leftFunc=function() QuitGame() end, func=function() self:RecreateAndConnect() end})

    elseif  self._isConnected and not self._isReconnecting then
        self._isConnected = false
        self:StopConnect()
        self:PrepareNetwork()
        self:Reconnect()
    end

    FireEvent(EventNames.NET_LOST, retCode)
end

function LNetManager:IsCanReconnect()
    return self._connectCounter >= 0
end

function LNetManager:IsReconnected()
    return self._connectedNum > 0
end

function LNetManager:CheckAlive()
    if self:IsConnected() then
        return true
    end

    if (not self:IsCanReconnect()) then
        return true
    end

    self:Connect()
end

function LNetManager:IsConnected()
    return self._isConnected
end

function LNetManager:IsNetworkClosing()
    return self._isNetworkClosing
end

function LNetManager:EnableResend()
    self._isEnableResend = true
end

function LNetManager:ResendLostMessages()
    local waitMsgList = self._waitMsgList
    local waitMsgMap = self._waitMsgMap

    self._waitMsgMap = {}
    self._waitMsgList = {}

    if self._isEnableResend then
        local ignoreMessageNames = {
            ["CombatReq"] = true,
            ["JoinGuildReq"] = true,
            ["HeroRebirthReq"] = true,
        }
        for k, protoId in ipairs(waitMsgList) do
            local waitData = waitMsgMap[protoId]
            if not ignoreMessageNames[waitData.name] then
                self:SendMessage(protoId, waitData.stream)
                if LOG_INFO_ENABLED then
                    printInfoN2(NETWORK_LOG_TAG, string.format("resend message, id = %8d", protoId))
                end
            end
        end
    end
end

function LNetManager:WaitResponse(protoId, msgName, stream)
    self._lastActiveTime = Time.realtimeSinceStartup

    if self._isEnableResend then
        local old = self._waitMsgMap[protoId]
        local data = { name = msgName, stream = stream }
        self._waitMsgMap[protoId] = data
        if old then
            table.removebyvalue(self._waitMsgList, protoId)
        end
        table.insert(self._waitMsgList, protoId)
    end

    self._isStartWait = true
    local waitSec = 10
    if CS.IsResModeEdit() then
        waitSec = LPlayerPrefs and tonumber(LPlayerPrefs.edtReconnect) or 100000
    end

    if  self._isPause then
        self._isStartWait = false
        self:ShowNetBlock(true, "", waitSec)
        return
    end

    self:ShowNetBlock(true, "", waitSec, function()
        self._isStartWait = false
        self:StopConnect(string.format("send message (name = %s) time out" , msgName))
        self:PrepareNetwork()
        self:Reconnect()
    end)
end

function LNetManager:OnResponse(protoId)
    protoId = protoId - 1
    local waitData = self._waitMsgMap[protoId]
    self._waitMsgMap[protoId] = nil
    self._isStartWait = false
    self:ShowNetBlock(false)
    if waitData then
        table.removebyvalue(self._waitMsgList, protoId)
        local stream = waitData.stream
        if stream then
            stream:Clear()
            stream = nil
        end
    end
end

function LNetManager:ShowNetBlock(bShow, msg, waitSec, cb)
    if bShow then
        GF.StartWait(waitSec, msg, cb)
    else
        GF.StopWait()
    end
end

function LNetManager:FormatPromptMsg(code, args)
    local str = ccServerText(code)
    local t = {}
    args = args or {}
    for i,v in ipairs(args) do t["a"..i] = v end
    for i,v in ipairs(args) do t["c"..i] = ccLngText(v) end
    for i,v in ipairs(args) do t["e"..i] = gModelItem:FormatItemListStr(v) end
    local ret = string.gsub(str,"#(%w+)#",t)
    return ret
end

function LNetManager:LogProtoMessage(protoId, proto, tips, compress)
    if not ENABLE_PROTO_LOG then
        return
    end
    local msgName = LProtoHelper.GetProtoName(protoId)
    local content = LProtoHelper.StackTrace(proto)
    local showMsg = string.format("[%s][%s] %s \n%s",YXTime.GetTimestampLogFormat(), tips, msgName, content)
    if (tips == "send") then
        printInfoN2(NETWORK_LOG_TAG,  FormatLogWithColor(showMsg, "8bee4bff"))
    elseif (tips == "receive") then
        if compress and compress > 0 then
            printInfoN2(NETWORK_LOG_TAG,  FormatLogWithColor(showMsg, "ff80ddff"))
        else
            printInfoN2(NETWORK_LOG_TAG,  FormatLogWithColor(showMsg, "6d80ddff"))
        end

    else
        printInfoN2(NETWORK_LOG_TAG, showMsg)
    end
end

function LNetManager:OnNetworkHandler(networkId ,netCode, protoMsg)
    if networkId ~= self._networkId then
        return
    end


    self:StopTimer(_NetTimer.WaitConnectTimeOut)

    if netCode == NETWORK_CONNECTED then
        self:StopTimer(_NetTimer.Reconnect)
        self:OnConnected()
        return
    end

    if netCode == NETWORK_RECEIVE_MESSAGE then
        self:StopTimer(_NetTimer.Reconnect)
        self:OnReceiveMessage(protoMsg)
        return
    end

    if netCode < NETWORK_CONNECT_FAIL then
        self:OnConnectFail()
        return
    end

    if netCode < NETWORK_OK then
        self:StopTimer(_NetTimer.Reconnect)
        self:OnNetworkLost(netCode)
        return
    end
end

function LNetManager:OnReceiveMessage(protoMsg)
    local msgResp = LProtoHelper.GetMsgRespProto()
    msgResp:ParseFromString(protoMsg:GetMessage())

    protoMsg:Dispose()
    protoMsg = nil

    local protoId = msgResp.cmdId
    local compress = msgResp.compress
    local msgData = msgResp.data

    local packError = msgResp.error
    local packSuccess = msgResp.success

    self:OnResponse(protoId)

    if packError and packError.code and packError.code > 0 then
        local errorMsg = self:FormatPromptMsg(packError.code, packError.args)
        LogWarn(string.format("[%s] message(%d, %s) | code=%d | reason=%s", "Network", tostring(protoId), LProtoHelper.GetProtoName(protoId), tostring(packError.code), tostring(errorMsg)))

        if not string.isempty(errorMsg) then
            if GF then
                GF.ShowMessage(errorMsg)
            end
        end
        FireEvent(EventNames.NET_ERROR_CODE,protoId,packError.code,packError.args,errorMsg)
        return
    end

    if packSuccess and packSuccess.code and packSuccess.code > 0 then
        local promptMsg = self:FormatPromptMsg(packSuccess.code, packSuccess.args)
        if not string.isempty(promptMsg) then
            if GF then
                GF.ShowMessage(promptMsg)
            end
        end
        return
    end

    if compress and compress > 0 then
        msgData = CS.XZlib_Decompress(msgData)
    end

    local proto = LProtoHelper.CreateProto(protoId)
    if proto then
        proto:ParseFromString(msgData)
        if ENABLE_PROTO_LOG then
            self:LogProtoMessage(protoId, proto, "receive", compress)
        end
        if self:IsConnected() then
            self:FireMessage(protoId, proto, MESSAGE_OK)
        else
            if LOG_INFO_ENABLED then
                printInfoN2(NETWORK_LOG_TAG, "network is not connected")
            end
        end
    end

    msgResp:Clear()
    msgResp = nil
end

function LNetManager:SendMessage(protoId, proto)
    if not proto or self:IsNetworkClosing() then return end
    if not proto then return end

    self._msgIndex = self._msgIndex + 1
    if self._msgIndex > 2147483647 then
        self._msgIndex = 1
    end

    local sign = ""
    if self._isInitServerTime and self._account then
        local key  = "key"
        sign = CS.md5FromString(self._msgIndex .. self._account .. self._serverTime64 .. key)
    end

    local msgReq = LProtoHelper.GetMsgReqProto()
    msgReq.cmdId = protoId
    msgReq.ind = self._msgIndex
    msgReq.sign = sign
    msgReq.identityId = self._account or ""
    msgReq.data = proto:SerializeToString()

    local protoMsg= PJXProtoMessage.New()
    protoMsg.networkId = self._networkId
    protoMsg.messageId = protoId
    protoMsg:SetMessage(msgReq:SerializeToString())

    if gModelNetDebug ~= nil and gModelNetDebug:IsNetDebug() then
        gModelNetDebug:AddDebugMessage(self._msgIndex, protoId, msgReq, proto)
        return
    end

    msgReq:Clear()
    msgReq = nil

    if not self:IsConnected() then
        return
    end

    YXNetMgr:Send(protoMsg)

    self:LogProtoMessage(protoId, proto, "send")
    self:WaitResponse(protoId, LProtoHelper.GetProtoName(protoId), proto)
end

function LNetManager:StopTimer(key)
    self._waitConnectTimer:TimerRemoveByKey(key)
end
function LNetManager:StartTimer(key, time, func, timeUnscale, loopCnt)
    self._waitConnectTimer:TimerRemoveByKey(key)
    self._waitConnectTimer:TimerCreate(key, func, time, timeUnscale, loopCnt)
end
function LNetManager:TimerFind(key)
    return self._waitConnectTimer:TimerGetByKey(key)
end

function LNetManager:SendTick()
    if not self:IsConnected() then return end
    local time = Time.realtimeSinceStartup
    if not self._lastActiveTime then
        self._lastActiveTime = 0
    end
    if time - self._lastActiveTime > 60 then
        self._lastActiveTime = time
        local pb = LProtoHelper.CreateProto(LProtoIds.TickReq)
        SendMessage(pb, LProtoIds.TickReq)
    end
end

function LNetManager:OnApplicationPause(isPause)
    self._isPause = isPause
    if (not isPause) then
        if (gLGameLogin and gLGameLogin:IsStartConnect()) then
            self:CheckAlive()
        end
    else
        if self._isStartWait then
            self._isStartWait = false
            self:ShowNetBlock(true, "", 10)
        end
    end

end

function LNetManager:GetReconnectCnt()
    return self._connectCounter
end

function LNetManager:SendMessagePackDebug(pbPack,proto,protoId,debugKey)
    if not pbPack or not proto then return end
    if self:IsNetworkClosing() then return end

    pbPack.ind = self._msgIndex
    self._msgIndex = self._msgIndex + 1
    if self._msgIndex > 2147483647 then
        self._msgIndex = 1
    end

    local sign = ""
    if self._isInitServerTime and self._account then
        local key = debugKey
        sign = CS.md5FromString(self._msgIndex .. self._account .. self._serverTime64 .. key)
    end
    pbPack.sign = sign
    pbPack.data = proto:SerializeToString()

    local protoMsg= PJXProtoMessage.New()
    protoMsg.networkId = self._networkId
    protoMsg.messageId = protoId
    protoMsg:SetMessage(pbPack:SerializeToString())
    pbPack:Clear()
    pbPack = nil

    YXNetMgr:Send(protoMsg)

    self:LogProtoMessage(protoId, proto, "send")
    self:WaitResponse(protoId, LProtoHelper.GetProtoName(protoId), proto)
end

function LNetManager:SendMessageBuffDebug(pbPackBuff,pbStream,protoId)
    if not pbStream or not pbPackBuff then return end
    if self:IsNetworkClosing() then return end

    self._msgIndex = self._msgIndex + 1
    if self._msgIndex > 2147483647 then
        self._msgIndex = 1
    end

    local protoMsg= PJXProtoMessage.New()
    protoMsg.networkId = self._networkId
    protoMsg.messageId = protoId
    protoMsg:SetMessage(pbPackBuff)
    pbStream:Clear()
    pbStream = nil
    pbPackBuff:Clear()
