    YXNetMgr:Send(protoMsg)

    self:LogProtoMessage(protoId, pbStream, "send")
    self:WaitResponse(protoId, LProtoHelper.GetProtoName(protoId), pbStream)
end

function LNetManager:SendMessageDebug(pbStream,protoId,bDebug,debugKey,debugIndex)
    if not pbStream or self:IsNetworkClosing() then return end

    if debugIndex then
        self._msgIndex = debugIndex
    end


    local msgReq = LProtoHelper.GetMsgReqProto()
    msgReq.messageId = protoId
    msgReq.ind = self._msgIndex
    local sign = ""
    if self._isInitServerTime and self._account then
        local key = debugKey
        sign = CS.md5FromString(self._msgIndex .. self._account .. self._serverTime64 .. key)
    end
    msgReq.sign = sign
    msgReq.data = pbStream:SerializeToString()

    self._msgIndex = self._msgIndex + 1
    if self._msgIndex > 2147483647 then
        self._msgIndex = 1
    end

    if not bDebug and gModelNetDebug ~= nil and gModelNetDebug:IsNetDebug() then
        local index = pbStream.ind
        gModelNetDebug:AddDebugMessage(index, protoId, msgReq, pbStream)
        return
    end

    local protoMsg= PJXProtoMessage.New()
    protoMsg.networkId = self._networkId
    protoMsg.messageId = protoId
    protoMsg:SetMessage(msgReq:SerializeToString())
    msgReq:Clear()
    msgReq = nil

    YXNetMgr:Send(protoMsg)

    self:LogProtoMessage(protoId, pbStream, "send")
    self:WaitResponse(protoId, LProtoHelper.GetProtoName(protoId), pbStream)
end

return LNetManager